import React, { useState, useEffect } from "react";
import { useNavigate } from 'react-router-dom';
import { Brain, MessageCircle, Calendar, Heart, Sparkles, User, Sun, Moon } from "lucide-react";
import { useTheme } from '../contexts/ThemeContext';
import CalendarPopup from './CalendarPopup';

export default function DashboardPage() {
  const navigate = useNavigate();
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [reflection, setReflection] = useState('');
  const [isCalendarOpen, setIsCalendarOpen] = useState(false);

  useEffect(() => {
    // Load reflection for the current date from localStorage
    const storedReflection = localStorage.getItem(`reflection_${selectedDate.toDateString()}`);
    setReflection(storedReflection || '');
  }, [selectedDate]);

  const formatDate = (date) => {
    const options = { 
      weekday: 'long', 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    };
    return date.toLocaleDateString('en-US', options);
  };

  const handlePreviousDay = () => {
    const newDate = new Date(selectedDate);
    newDate.setDate(newDate.getDate() - 1);
    setSelectedDate(newDate);
  };

  const handleNextDay = () => {
    const newDate = new Date(selectedDate);
    newDate.setDate(newDate.getDate() + 1);
    setSelectedDate(newDate);
  };

  const handleChatClick = () => {
    navigate('/chat');
  };

  const handleHistoryClick = () => {
    navigate('/history');
  };

  const handleProfileClick = () => {
    navigate('/profile');
  };

  const handleCalendarClick = () => {
    setIsCalendarOpen(true);
  };

  const handleDateSelect = (date) => {
    setSelectedDate(date);
    setIsCalendarOpen(false);
  };

  return (
    <div
      className="min-h-screen px-6 py-8 relative overflow-hidden slide-up"
      style={{
        background: "linear-gradient(to bottom, #0B0E14 0%, #1C1F2E 100%)",
      }}
    >
      <div className="absolute inset-0 overflow-hidden">
        {/* Flowing cloud outlines - barely visible */}
        <div className="absolute top-20 left-16 opacity-15">
          <svg width="60" height="30" viewBox="0 0 60 30" fill="none" stroke="#7DD3C0" strokeWidth="0.5">
            <path d="M8 18c0-6 4-10 10-10s10 4 10 10c0 3-2 6-5 8H13c-3-2-5-5-5-8z" />
            <path d="M25 15c0-4 3-7 7-7s7 3 7 7c0 2-1 4-3 5H28c-2-1-3-3-3-5z" />
            <path d="M40 12c0-3 2-5 5-5s5 2 5 5c0 1.5-0.5 3-2 4H42c-1.5-1-2-2.5-2-4z" />
          </svg>
        </div>

        <div className="absolute top-40 right-20 opacity-12">
          <svg width="80" height="25" viewBox="0 0 80 25" fill="none" stroke="#D4AF37" strokeWidth="0.4">
            <path d="M5 15c0-5 3-8 8-8s8 3 8 8c0 2.5-1.5 5-4 6.5H9c-2.5-1.5-4-4-4-6.5z" />
            <path d="M20 12c0-4 2.5-6 6-6s6 2 6 6c0 2-1 4-2.5 5H22.5c-1.5-1-2.5-3-2.5-5z" />
            <path d="M35 10c0-3 2-5 5-5s5 2 5 5c0 1.5-0.5 3-2 4H37c-1.5-1-2-2.5-2-4z" />
            <path d="M50 13c0-4 3-7 7-7s7 3 7 7c0 2-1 4-3 5H53c-2-1-3-3-3-5z" />
          </svg>
        </div>

        <div className="absolute bottom-32 left-12 opacity-14">
          <svg width="70" height="28" viewBox="0 0 70 28" fill="none" stroke="#9BB5FF" strokeWidth="0.5">
            <path d="M6 17c0-5.5 3.5-9 9-9s9 3.5 9 9c0 2.8-1.5 5.5-4 7H10c-2.5-1.5-4-4.2-4-7z" />
            <path d="M22 14c0-4 2.5-6.5 6.5-6.5s6.5 2.5 6.5 6.5c0 2-1 4-2.5 5H24.5c-1.5-1-2.5-3-2.5-5z" />
            <path d="M40 11c0-3 2-5 5-5s5 2 5 5c0 1.5-0.5 3-2 4H42c-1.5-1-2-2.5-2-4z" />
          </svg>
        </div>

        {/* Flowing spark waves - semi-transparent line art */}
        <div className="absolute top-60 left-8 opacity-10">
          <svg width="100" height="15" viewBox="0 0 100 15" fill="none" stroke="#7DD3C0" strokeWidth="0.6">
            <path d="M2 7.5c8-3 16 3 24-3s16 3 24-3s16 3 24-3s16 3 24 3" />
            <path d="M5 5c6-2 12 2 18-2s12 2 18-2s12 2 18-2s12 2 18 2" opacity="0.4" />
            <circle cx="15" cy="4" r="0.8" fill="#7DD3C0" opacity="0.3" />
            <circle cx="45" cy="10" r="0.8" fill="#7DD3C0" opacity="0.3" />
            <circle cx="75" cy="6" r="0.8" fill="#7DD3C0" opacity="0.3" />
          </svg>
        </div>

        <div className="absolute bottom-48 right-16 opacity-11">
          <svg width="90" height="18" viewBox="0 0 90 18" fill="none" stroke="#D4AF37" strokeWidth="0.5">
            <path d="M3 9c7-2.5 14 2.5 21-2.5s14 2.5 21-2.5s14 2.5 21-2.5s14 2.5 21 2.5" />
            <path d="M8 6c5-1.5 10 1.5 15-1.5s10 1.5 15-1.5s10 1.5 15-1.5s10 1.5 15 1.5" opacity="0.5" />
            <circle cx="25" cy="7" r="0.6" fill="#D4AF37" opacity="0.4" />
            <circle cx="55" cy="11" r="0.6" fill="#D4AF37" opacity="0.4" />
          </svg>
        </div>

        <div className="absolute top-80 right-24 opacity-13">
          <svg width="85" height="20" viewBox="0 0 85 20" fill="none" stroke="#9BB5FF" strokeWidth="0.6">
            <path d="M4 10c6-2 12 2 18-2s12 2 18-2s12 2 18-2s12 2 18-2s12 2 15 2" />
            <path d="M10 7c4-1 8 1 12-1s8 1 12-1s8 1 12-1s8 1 12-1s8 1 10 1" opacity="0.6" />
            <circle cx="30" cy="8" r="0.7" fill="#9BB5FF" opacity="0.3" />
            <circle cx="60" cy="12" r="0.7" fill="#9BB5FF" opacity="0.3" />
          </svg>
        </div>

        {/* Additional subtle cloud formations */}
        <div className="absolute top-32 left-32 opacity-12">
          <svg width="50" height="22" viewBox="0 0 50 22" fill="none" stroke="#7DD3C0" strokeWidth="0.4">
            <path d="M5 13c0-4 3-7 7-7s7 3 7 7c0 2-1 4-3 5H8c-2-1-3-3-3-5z" />
            <path d="M18 11c0-3 2-5 5-5s5 2 5 5c0 1.5-0.5 3-2 4H20c-1.5-1-2-2.5-2-4z" />
            <path d="M30 9c0-2.5 1.5-4 4-4s4 1.5 4 4c0 1.2-0.3 2.5-1.5 3H31.5c-1.2-0.5-1.5-1.8-1.5-3z" />
          </svg>
        </div>

        <div className="absolute bottom-60 right-32 opacity-11">
          <svg width="65" height="24" viewBox="0 0 65 24" fill="none" stroke="#D4AF37" strokeWidth="0.4">
            <path d="M6 14c0-4.5 3-7.5 7.5-7.5s7.5 3 7.5 7.5c0 2.2-1 4.5-3 6H9c-2-1.5-3-3.8-3-6z" />
            <path d="M20 12c0-3.5 2.5-6 6-6s6 2.5 6 6c0 1.8-0.8 3.5-2.5 4.5H22.5c-1.7-1-2.5-2.7-2.5-4.5z" />
            <path d="M35 10c0-3 2-5 5-5s5 2 5 5c0 1.5-0.5 3-2 4H37c-1.5-1-2-2.5-2-4z" />
          </svg>
        </div>
      </div>

      <div className="relative z-10 max-w-sm mx-auto">
        <div className="flex justify-between items-center mb-8">
          <div
            onClick={handleHistoryClick}
            className="w-10 h-10 rounded-full flex items-center justify-center backdrop-blur-md cursor-pointer hover:opacity-80 transition-opacity"
            style={{
              backgroundColor: "rgba(28, 31, 46, 0.4)",
              boxShadow: "inset 0 0 20px rgba(125, 211, 192, 0.15), 0 8px 32px rgba(125, 211, 192, 0.1)",
              border: "1px solid rgba(125, 211, 192, 0.2)",
            }}
          >
            <Heart className="w-5 h-5" style={{ color: "#7DD3C0" }} strokeWidth={1.5} />
          </div>

          <div
            className="w-14 h-14 rounded-full flex items-center justify-center backdrop-blur-md"
            style={{
              backgroundColor: "rgba(28, 31, 46, 0.5)",
              boxShadow: "inset 0 0 25px rgba(212, 175, 55, 0.2), 0 12px 40px rgba(212, 175, 55, 0.15)",
              border: "1px solid rgba(212, 175, 55, 0.25)",
            }}
          >
            <Brain className="w-7 h-7" style={{ color: "#D4AF37" }} strokeWidth={1.5} />
          </div>

          <div className="flex space-x-2">
            <div
              className="w-10 h-10 rounded-full flex items-center justify-center backdrop-blur-md cursor-pointer hover:opacity-80 transition-opacity"
              style={{
                backgroundColor: "rgba(28, 31, 46, 0.4)",
                boxShadow: "inset 0 0 20px rgba(155, 181, 255, 0.15), 0 8px 32px rgba(155, 181, 255, 0.1)",
                border: "1px solid rgba(155, 181, 255, 0.2)",
              }}
            >
              <Sparkles className="w-5 h-5" style={{ color: "#9BB5FF" }} strokeWidth={1.5} />
            </div>
            <div
              onClick={handleProfileClick}
              className="w-10 h-10 rounded-full flex items-center justify-center backdrop-blur-md cursor-pointer hover:opacity-80 transition-opacity"
              style={{
                backgroundColor: "rgba(28, 31, 46, 0.4)",
                boxShadow: "inset 0 0 20px rgba(125, 211, 192, 0.15), 0 8px 32px rgba(125, 211, 192, 0.1)",
                border: "1px solid rgba(125, 211, 192, 0.2)",
              }}
            >
              <User className="w-5 h-5" style={{ color: "#7DD3C0" }} strokeWidth={1.5} />
            </div>
          </div>
        </div>

        <div
          className="rounded-2xl p-4 mb-6 relative overflow-hidden backdrop-blur-lg"
          style={{
            backgroundColor: "rgba(28, 31, 46, 0.3)",
            boxShadow: "inset 0 0 30px rgba(125, 211, 192, 0.12), 0 16px 48px rgba(125, 211, 192, 0.08)",
            border: "1px solid rgba(125, 211, 192, 0.18)",
          }}
        >
          <div className="flex items-center justify-between text-white">
            <button 
              onClick={handlePreviousDay}
              className="p-1 hover:bg-gray-800/30 rounded transition-colors"
            >
              <span className="text-lg text-gray-300">‹</span>
            </button>
            <div 
              className="text-center cursor-pointer hover:bg-gray-800/20 rounded-xl p-2 transition-colors"
              onClick={handleCalendarClick}
            >
              <div className="flex items-center justify-center space-x-2 mb-1">
                <Calendar className="w-4 h-4" style={{ color: "#7DD3C0" }} />
                <span className="text-sm text-gray-300">Selected Date</span>
              </div>
              <div className="font-semibold text-white">{formatDate(selectedDate)}</div>
              <div className="text-xs text-gray-400">Click to open calendar</div>
            </div>
            <button 
              onClick={handleNextDay}
              className="p-1 hover:bg-gray-800/30 rounded transition-colors"
            >
              <span className="text-lg text-gray-300">›</span>
            </button>
          </div>
        </div>

        <div
          className="rounded-2xl p-6 mb-6 relative overflow-hidden backdrop-blur-lg"
          style={{
            backgroundColor: "rgba(28, 31, 46, 0.35)",
            boxShadow: "inset 0 0 35px rgba(212, 175, 55, 0.15), 0 20px 60px rgba(212, 175, 55, 0.1)",
            border: "1px solid rgba(212, 175, 55, 0.2)",
          }}
        >
          <div className="flex items-center space-x-3 mb-4">
            <div
              className="w-8 h-8 rounded-full flex items-center justify-center backdrop-blur-sm"
              style={{
                backgroundColor: "rgba(212, 175, 55, 0.8)",
                boxShadow: "0 0 20px rgba(212, 175, 55, 0.4), inset 0 0 10px rgba(255, 255, 255, 0.2)",
              }}
            >
              <span className="text-black text-sm">⚡</span>
            </div>
            <h2 className="text-lg font-semibold text-white">Day's Reflect</h2>
          </div>
          <div
            className="rounded-xl p-5 min-h-24 relative overflow-hidden backdrop-blur-lg"
            style={{
              backgroundColor: "rgba(11, 14, 20, 0.6)",
              border: "1px solid rgba(155, 181, 255, 0.15)",
              boxShadow: "inset 0 0 25px rgba(155, 181, 255, 0.08)",
            }}
          >
            {reflection ? (
              <p className="text-gray-300 text-sm leading-relaxed">{reflection}</p>
            ) : (
              <div className="flex flex-col items-center justify-center h-full">
                <div
                  className="w-12 h-12 rounded-lg flex items-center justify-center mb-3 backdrop-blur-md"
                  style={{
                    backgroundColor: "rgba(28, 31, 46, 0.5)",
                    boxShadow: "inset 0 0 20px rgba(125, 211, 192, 0.12), 0 8px 32px rgba(125, 211, 192, 0.08)",
                    border: "1px solid rgba(125, 211, 192, 0.18)",
                  }}
                >
                  <span className="text-2xl">🌿</span>
                </div>
                <p className="text-gray-300 text-sm text-center italic">Take a mindful moment to reflect 🧘‍♀️</p>
              </div>
            )}
          </div>
        </div>

        <div className="flex justify-center">
          <button
            onClick={handleChatClick}
            className="flex items-center space-x-3 text-white font-medium rounded-2xl px-8 py-4 hover:opacity-90 transition-all duration-300 w-full justify-center relative overflow-hidden backdrop-blur-lg"
            style={{
              background:
                "linear-gradient(135deg, rgba(125, 211, 192, 0.8) 0%, rgba(212, 175, 55, 0.8) 50%, rgba(155, 181, 255, 0.8) 100%)",
              boxShadow: "inset 0 0 30px rgba(255, 255, 255, 0.1), 0 16px 48px rgba(125, 211, 192, 0.2)",
              color: "#0B0E14",
              border: "1px solid rgba(255, 255, 255, 0.15)",
            }}
          >
            <MessageCircle className="w-5 h-5" />
            <span>Chat with Deite</span>
            <span className="text-lg">💬</span>
          </button>
        </div>
      </div>

      {/* Calendar Popup */}
      <CalendarPopup
        isOpen={isCalendarOpen}
        onClose={() => setIsCalendarOpen(false)}
        selectedDate={selectedDate}
        onDateSelect={handleDateSelect}
      />
    </div>
  );
}
